package generated_test

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/odvcencio/gts-suite/pkg/generated"
	"github.com/odvcencio/gts-suite/pkg/index"
)

func TestIntegration_IndexBuildDetectsGenerated(t *testing.T) {
	dir := t.TempDir()

	// Human-written file
	writeFile(t, dir, "main.go", "package main\n\nfunc main() {}\n")

	// Generated file — Go convention marker
	writeFile(t, dir, "gen.go", "// Code generated by stringer -type=Color; DO NOT EDIT.\npackage main\n\nfunc _() {}\n")

	// Protobuf file — filename pattern
	writeFile(t, dir, "user.pb.go", "package main\n\ntype User struct{}\n")

	builder := index.NewBuilder()
	builder.SetDetector(generated.NewDetector(nil))
	idx, err := builder.BuildPath(dir)
	if err != nil {
		t.Fatal(err)
	}

	genCount := idx.GeneratedFileCount()
	if genCount != 2 {
		t.Errorf("expected 2 generated files, got %d", genCount)
		for _, f := range idx.Files {
			t.Logf("  %s generated=%v", f.Path, f.Generated)
		}
	}

	filtered := idx.WithoutGenerated()
	if len(filtered.Files) != 1 {
		t.Errorf("expected 1 human file after filter, got %d", len(filtered.Files))
	}

	// Verify the generators are correct
	for _, f := range idx.Files {
		if f.Path == "gen.go" && (f.Generated == nil || f.Generated.Generator != "go-generate") {
			t.Errorf("gen.go: expected go-generate, got %v", f.Generated)
		}
		if f.Path == "user.pb.go" && (f.Generated == nil || f.Generated.Generator != "protobuf") {
			t.Errorf("user.pb.go: expected protobuf, got %v", f.Generated)
		}
		if f.Path == "main.go" && f.Generated != nil {
			t.Errorf("main.go: expected nil Generated, got %v", f.Generated)
		}
	}
}

func TestIntegration_ConfigOverridesBuiltin(t *testing.T) {
	dir := t.TempDir()

	writeFile(t, dir, "main.go", "package main\n\nfunc main() {}\n")
	writeFile(t, dir, "custom.go", "package main\n\nfunc Custom() {}\n")

	configs := []generated.ConfigEntry{
		{Generator: "custom-tool", Pattern: "custom.go"},
	}
	builder := index.NewBuilder()
	builder.SetDetector(generated.NewDetector(configs))
	idx, err := builder.BuildPath(dir)
	if err != nil {
		t.Fatal(err)
	}

	for _, f := range idx.Files {
		if f.Path == "custom.go" {
			if f.Generated == nil {
				t.Fatal("custom.go should be detected as generated via config")
			}
			if f.Generated.Generator != "custom-tool" {
				t.Errorf("expected custom-tool, got %s", f.Generated.Generator)
			}
			if f.Generated.Reason != "config" {
				t.Errorf("expected config reason, got %s", f.Generated.Reason)
			}
		}
	}
}

func writeFile(t *testing.T, dir, name, content string) {
	t.Helper()
	path := filepath.Join(dir, name)
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}
